<script>
(function(){
  var btn=document.getElementById('jha-open-nav');
  var ov=document.getElementById('jha-overlay');
  var cls=document.getElementById('jha-close-nav');
  if(!btn||!ov||!cls) return;
  if(ov.parentNode!==document.body) document.body.appendChild(ov);

  function openMenu(){ ov.style.display='flex'; document.body.style.overflow='hidden'; }
  function closeMenu(){ ov.style.display='none'; document.body.style.overflow=''; }
  btn.addEventListener('click',openMenu);
  cls.addEventListener('click',closeMenu);
  ov.addEventListener('click',function(e){ if(e.target===ov) closeMenu(); });
  document.addEventListener('keydown',function(e){ if(e.key==='Escape') closeMenu(); });

  // Hover animations
  var topLinks=ov.querySelectorAll('.jha-nav-top');
  var subLinks=ov.querySelectorAll('.jha-nav-sub');

  topLinks.forEach(function(a){
    a.addEventListener('mouseenter',function(){
      a.style.color='#0E672A';
      a.style.paddingLeft='10px';
    });
    a.addEventListener('mouseleave',function(){
      a.style.color='#111827';
      a.style.paddingLeft='0px';
    });
  });

  subLinks.forEach(function(a){
    a.addEventListener('mouseenter',function(){
      a.style.color='#0E672A';
      a.style.paddingLeft='28px';
    });
    a.addEventListener('mouseleave',function(){
      a.style.color='#555555';
      a.style.paddingLeft='20px';
    });
  });
})();
</script>
