/* ── button2: text-style green underline button ───────────────────── */
.button2 a.elementor-button,
.button2 a.elementor-button:visited {
  background-color: transparent !important;
  color: #0E672A !important;
  border: none !important;
  border-bottom: 2px solid #0E672A !important;
  border-radius: 0 !important;
  padding: 4px 4px !important;
  font-size: 15px !important;
  font-weight: 600 !important;
  font-family: Inter, sans-serif !important;
  box-shadow: none !important;
  text-decoration: none !important;
  display: inline-block !important;
}
.button2 a.elementor-button:hover {
  color: #0B5523 !important;
  border-bottom-color: #0B5523 !important;
  background-color: transparent !important;
}
/* ── button2: text-style green underline button ───────────────────── */
.elementor-widget-button.button2 a.elementor-button,
.elementor-widget-button.button2 a.elementor-button:visited,
.button2 a.elementor-button,
.button2 a.elementor-button:visited {
  background-color: transparent !important;
  background-image: none !important;
  color: #0E672A !important;
  border: none !important;
  border-bottom: 2px solid #0E672A !important;
  border-radius: 0 !important;
  padding: 4px 4px !important;
  font-size: 15px !important;
  font-weight: 600 !important;
  font-family: Inter, sans-serif !important;
  box-shadow: none !important;
  text-decoration: none !important;
  display: inline-block !important;
}
.elementor-widget-button.button2 a.elementor-button:hover,
.button2 a.elementor-button:hover {
  color: #0B5523 !important;
  border-bottom-color: #0B5523 !important;
  background-color: transparent !important;
  background-image: none !important;
}

