<script>
(function(){
  var GREEN="#0E672A",DARK="#111827";
  var map=[
    {gid:"yc-g-sounds", target:"sounds"},
    {gid:"yc-g-ablaze", target:"ablaze"},
    {gid:"yc-g-tribe",  target:"tribe"},
    {gid:"yc-g-vizion", target:"vizion"}
  ];
  function init(){
    map.forEach(function(m){
      var g=document.getElementById(m.gid);
      if(!g) return;
      var txt=g.querySelector("text");
      var ln=g.querySelector("line");
      if(txt){txt.style.transition="fill 0.25s";txt.style.fill=DARK;}
      if(ln){ln.style.transition="opacity 0.25s";ln.style.opacity="0";}
      g.addEventListener("mouseenter",function(){if(txt)txt.style.fill=GREEN;if(ln)ln.style.opacity="1";});
      g.addEventListener("mouseleave",function(){if(txt)txt.style.fill=DARK;if(ln)ln.style.opacity="0";});
      g.addEventListener("click",function(){
        var el=document.getElementById(m.target);
        if(el)el.scrollIntoView({behavior:"smooth",block:"start"});
      });
    });
  }
  if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",init);}else{init();}
